(function () {
'use strict';
const Phaser = window.Phaser;
if (!Phaser) {
  throw new Error('Phaser missing — open DickKicker-offline.html or use index-offline.html in this folder.');
}


/**
 * Procedural level config for levels 1–80.
 * L1: 50 slow straight drops. L2: ~100 with mixed speed. L80: ~400, fast, varied trajectories.
 */
function getLevelConfig(level) {
  const clampedLevel = Math.max(1, Math.min(80, level));
  const t = (clampedLevel - 1) / 79;

  let totalObjects;
  if (clampedLevel === 1) {
    totalObjects = 50;
  } else if (clampedLevel === 2) {
    totalObjects = 100;
  } else {
    totalObjects = Math.round(100 + ((clampedLevel - 2) / 78) * 300);
  }

  let spawnIntervalMs;
  if (clampedLevel === 1) {
    spawnIntervalMs = 1200;
  } else if (clampedLevel === 2) {
    spawnIntervalMs = 800;
  } else {
    spawnIntervalMs = Math.round(800 - ((clampedLevel - 2) / 78) * 550);
  }

  const speedMin = clampedLevel === 1 ? 80 : clampedLevel === 2 ? 80 : Math.round(80 + t * 40);
  const speedMax = clampedLevel === 1 ? 100 : clampedLevel === 2 ? 180 : Math.round(120 + t * 280);

  return {
    level: clampedLevel,
    totalObjects,
    spawnIntervalMs: Math.max(200, spawnIntervalMs),
    speedMin,
    speedMax,
    fastRatio: clampedLevel === 1 ? 0 : clampedLevel === 2 ? 0.35 : Math.min(0.85, 0.35 + t * 0.5),
    diagonalChance: clampedLevel < 10 ? 0 : Math.min(0.7, (clampedLevel - 10) * 0.015),
    bounceChance: clampedLevel < 25 ? 0 : Math.min(0.5, (clampedLevel - 25) * 0.012),
  };
}

const MAX_LEVEL = 80;

function saveProgress(level, score) {
  try {
    localStorage.setItem('dickkicker_level', String(level));
    const prev = Number(localStorage.getItem('dickkicker_highscore') || 0);
    if (score > prev) {
      localStorage.setItem('dickkicker_highscore', String(score));
    }
  } catch {
    // ignore storage errors
  }
}

function loadProgress() {
  try {
    return {
      level: Math.max(1, Math.min(MAX_LEVEL, Number(localStorage.getItem('dickkicker_level') || 1))),
      highScore: Number(localStorage.getItem('dickkicker_highscore') || 0),
    };
  } catch {
    return { level: 1, highScore: 0 };
  }
}

function resetProgress() {
  try {
    localStorage.removeItem('dickkicker_level');
    localStorage.removeItem('dickkicker_highscore');
  } catch {
    // ignore
  }
}


const PIXEL_SCALE = 3;
const FOOT_DISPLAY_SCALE = 0.5;

const SOURCE_TARGETS = {
  foot: 34,
  dick: 26,
};

/** @type {{ foot: SpriteConfig, dick: SpriteConfig }} */
let SPRITES = buildDefaultSprites();

function buildSpriteConfig(key, pixelWidth, pixelHeight) {
  let displayWidth = pixelWidth * PIXEL_SCALE;
  let displayHeight = pixelHeight * PIXEL_SCALE;

  if (key === 'foot') {
    displayWidth = Math.round(displayWidth * FOOT_DISPLAY_SCALE);
    displayHeight = Math.round(displayHeight * FOOT_DISPLAY_SCALE);
  }

  const bodyWidth = key === 'foot' ? displayWidth : Math.round(displayWidth * 0.84);
  const bodyHeight = key === 'foot' ? displayHeight : Math.round(displayHeight * 0.86);
  const bodyOffsetX = key === 'foot' ? 0 : Math.round((displayWidth - bodyWidth) / 2);
  const bodyOffsetY = key === 'foot' ? 0 : Math.round((displayHeight - bodyHeight) / 2);

  return {
    key,
    pixelWidth,
    pixelHeight,
    displayWidth,
    displayHeight,
    bodyWidth,
    bodyHeight,
    bodyOffsetX,
    bodyOffsetY,
  };
}

function buildDefaultSprites() {
  return {
    foot: buildSpriteConfig('foot', 34, 60),
    dick: buildSpriteConfig('dick', 26, 22),
  };
}

function applySpriteMetrics(metrics) {
  SPRITES = {
    foot: buildSpriteConfig('foot', metrics.foot.pixelWidth, metrics.foot.pixelHeight),
    dick: buildSpriteConfig('dick', metrics.dick.pixelWidth, metrics.dick.pixelHeight),
  };
  return SPRITES;
}

/** Playfield bounds aligned strictly to the inner border outline. */
function getBounceBounds(width, height, border = 12) {
  return {
    x: border,
    y: border,
    width: width - border * 2,
    height: height - border * 2,
    insetX: border,
  };
}

/** Horizontal movement limits for the foot (strictly its outline width). */
function getFootMoveLimits(screenWidth) {
  const half = SPRITES.foot.displayWidth / 2;
  return { min: half, max: screenWidth - half };
}


/**
 * Extract white-on-black art → transparent pixel sprite (nearest-neighbor).
 */
function makePixelTexture(scene, sourceKey, destKey, targetPixelWidth, threshold = 140) {
  const src = scene.textures.get(sourceKey).getSourceImage();
  const sw = src.width;
  const sh = src.height;

  const read = document.createElement('canvas');
  read.width = sw;
  read.height = sh;
  const readCtx = read.getContext('2d', { willReadFrequently: true });
  readCtx.drawImage(src, 0, 0);

  const source = readCtx.getImageData(0, 0, sw, sh);
  const { data } = source;
  let minX = sw;
  let minY = sh;
  let maxX = 0;
  let maxY = 0;

  for (let y = 0; y < sh; y += 1) {
    for (let x = 0; x < sw; x += 1) {
      const i = (y * sw + x) * 4;
      const lum = (data[i] + data[i + 1] + data[i + 2]) / 3;
      if (lum >= threshold) {
        data[i] = 255;
        data[i + 1] = 255;
        data[i + 2] = 255;
        data[i + 3] = 255;
        minX = Math.min(minX, x);
        maxX = Math.max(maxX, x);
        minY = Math.min(minY, y);
        maxY = Math.max(maxY, y);
      } else {
        data[i + 3] = 0;
      }
    }
  }

  if (maxX < minX || maxY < minY) {
    throw new Error(`No shape found in texture: ${sourceKey}`);
  }

  readCtx.putImageData(source, 0, 0);

  const cropW = maxX - minX + 1;
  const cropH = maxY - minY + 1;
  const crop = document.createElement('canvas');
  crop.width = cropW;
  crop.height = cropH;
  const cropCtx = crop.getContext('2d');
  cropCtx.drawImage(read, minX, minY, cropW, cropH, 0, 0, cropW, cropH);

  const targetPixelHeight = Math.max(1, Math.round(cropH * (targetPixelWidth / cropW)));
  const out = document.createElement('canvas');
  out.width = targetPixelWidth;
  out.height = targetPixelHeight;
  const outCtx = out.getContext('2d');
  outCtx.imageSmoothingEnabled = false;
  outCtx.drawImage(crop, 0, 0, cropW, cropH, 0, 0, targetPixelWidth, targetPixelHeight);

  if (scene.textures.exists(destKey)) {
    scene.textures.remove(destKey);
  }
  scene.textures.addCanvas(destKey, out);

  const texture = scene.textures.get(destKey);
  if (texture?.setFilter) {
    texture.setFilter(1);
  }

  return {
    key: destKey,
    pixelWidth: targetPixelWidth,
    pixelHeight: targetPixelHeight,
  };
}


let engine = null;

class AudioEngine {
  constructor() {
    this.ready = false;
    this.ctx = null;
    this.master = null;
    this.musicGain = null;
    this.sfxGain = null;
    this.musicStep = 0;
    this.musicEvent = null;
    this.musicScene = null;
    this.musicMuted = false;
  }

  unlock(scene) {
    if (this.ready) {
      if (this.ctx.state === 'suspended') {
        this.ctx.resume();
      }
      this.ensureMusic(scene);
      return;
    }

    const AC = window.AudioContext || window.webkitAudioContext;
    if (!AC) return;

    this.ctx = new AC();
    this.master = this.ctx.createGain();
    this.master.gain.value = 0.4;
    this.master.connect(this.ctx.destination);

    this.musicGain = this.ctx.createGain();
    this.musicGain.gain.value = 0.28;
    this.musicGain.connect(this.master);

    this.sfxGain = this.ctx.createGain();
    this.sfxGain.gain.value = 0.55;
    this.sfxGain.connect(this.master);

    this.ready = true;
    this.ensureMusic(scene);
  }

  ensureMusic(scene) {
    if (!this.ready || !scene) return;
    if (this.musicScene === scene && this.musicEvent) return;

    if (this.musicEvent) {
      this.musicEvent.remove(false);
      this.musicEvent = null;
    }

    this.musicScene = scene;
    this.tickMusic();
    this.musicEvent = scene.time.addEvent({
      delay: 180,
      loop: true,
      callback: () => this.tickMusic(),
    });
  }

  tone(freq, duration, type = 'square', volume = 0.18, dest = this.sfxGain, when = null) {
    if (!this.ready || this.musicMuted && dest === this.musicGain) return;

    const t0 = when ?? this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(freq, t0);
    gain.gain.setValueAtTime(volume, t0);
    gain.gain.exponentialRampToValueAtTime(0.001, t0 + duration);

    osc.connect(gain);
    gain.connect(dest);
    osc.start(t0);
    osc.stop(t0 + duration + 0.02);
  }

  playKick() {
    if (!this.ready) return;
    const t = this.ctx.currentTime;
    this.tone(160, 0.07, 'square', 0.28, this.sfxGain, t);
    this.tone(520, 0.09, 'sawtooth', 0.14, this.sfxGain, t + 0.02);
    this.tone(90, 0.05, 'triangle', 0.2, this.sfxGain, t);
  }

  playBounce() {
    if (!this.ready) return;
    const t = this.ctx.currentTime;
    this.tone(240, 0.05, 'triangle', 0.2, this.sfxGain, t);
    this.tone(320, 0.08, 'square', 0.12, this.sfxGain, t + 0.03);
  }

  playAw() {
    if (!this.ready) return;
    const t = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(420, t);
    osc.frequency.exponentialRampToValueAtTime(160, t + 0.32);
    gain.gain.setValueAtTime(0.24, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.32);
    osc.connect(gain);
    gain.connect(this.sfxGain);
    osc.start(t);
    osc.stop(t + 0.34);
    this.tone(280, 0.12, 'triangle', 0.1, this.sfxGain, t + 0.08);
    this.tone(180, 0.2, 'square', 0.08, this.sfxGain, t + 0.12);
  }

  tickMusic() {
    if (!this.ready || this.musicMuted) return;

    const melody = [262, 262, 330, 294, 262, 294, 330, 349, 392, 349, 330, 294, 262, 220, 247, 262];
    const bass = [131, 131, 165, 147, 131, 147, 165, 175, 196, 175, 165, 147, 131, 110, 123, 131];
    const arp = [523, 659, 784, 659, 523, 659, 784, 988];
    const i = this.musicStep % melody.length;

    this.tone(melody[i], 0.16, 'square', 0.1, this.musicGain);
    this.tone(bass[i], 0.18, 'triangle', 0.14, this.musicGain);
    this.tone(arp[i % arp.length], 0.08, 'square', 0.05, this.musicGain);

    if (i % 4 === 0) {
      this.tone(65, 0.22, 'sawtooth', 0.08, this.musicGain);
    }

    this.musicStep += 1;
  }

  pauseMusic() {
    this.musicMuted = true;
    if (this.musicEvent) this.musicEvent.paused = true;
  }

  resumeMusic() {
    this.musicMuted = false;
    if (this.musicEvent) this.musicEvent.paused = false;
  }

  stopMusic() {
    if (this.musicEvent) {
      this.musicEvent.remove(false);
      this.musicEvent = null;
    }
    this.musicScene = null;
  }
}

function getAudio() {
  if (!engine) engine = new AudioEngine();
  return engine;
}

function unlockAudio(scene) {
  getAudio().unlock(scene);
}




const TRAJECTORY = {
  STRAIGHT: 'straight',
  DIAGONAL: 'diagonal',
  BOUNCE: 'bounce',
};

function enableWallBounce(obj) {
  obj.setBounce(1, 0);
  obj.setCollideWorldBounds(true);
  obj.body.setCollideWorldBounds(true, true, true, false, false);
  obj.body.onWorldBounds = true;
  obj.setData('wallBounce', true);
}

function pickSpeed(config) {
  const min = config.speedMin;
  const max = Math.max(config.speedMin, config.speedMax);
  return Phaser.Math.Between(min, max);
}

function createFallObject(group, x, y, config) {
  const obj = group.get(x, y, SPRITES.dick.key);
  if (!obj) return null;

  obj.setDisplaySize(SPRITES.dick.displayWidth, SPRITES.dick.displayHeight);
  obj.setActive(true);
  obj.setVisible(true);
  obj.setDepth(5);
  obj.setData('kicked', false);
  obj.setData('missed', false);
  obj.setData('hasBouncedFoot', false);
  obj.setData('lastFootBounce', 0);
  obj.setData('wallBounce', false);
  obj.body.enable = true;
  obj.body.setAllowGravity(false);
  obj.body.setImmovable(false);
  obj.body.setSize(SPRITES.dick.bodyWidth, SPRITES.dick.bodyHeight);
  obj.body.setOffset(SPRITES.dick.bodyOffsetX, SPRITES.dick.bodyOffsetY);

  const speed = pickSpeed(config);
  let trajectory = TRAJECTORY.STRAIGHT;

  const roll = Math.random();
  if (roll < config.bounceChance) {
    trajectory = TRAJECTORY.BOUNCE;
  } else if (roll < config.bounceChance + config.diagonalChance) {
    trajectory = TRAJECTORY.DIAGONAL;
  }

  obj.setData('trajectory', trajectory);

  switch (trajectory) {
    case TRAJECTORY.DIAGONAL: {
      const vx = Phaser.Math.Between(-speed * 0.6, speed * 0.6);
      obj.setVelocity(vx, speed);
      enableWallBounce(obj);
      break;
    }
    case TRAJECTORY.BOUNCE: {
      const vx = Phaser.Math.RND.sign() * Phaser.Math.Between(speed * 0.35, speed * 0.55);
      obj.setVelocity(vx, speed * 0.9);
      enableWallBounce(obj);
      break;
    }
    default:
      obj.setVelocity(0, speed);
      obj.setBounce(0, 0);
      obj.setCollideWorldBounds(false);
      break;
  }

  return obj;
}

function releaseFallObject(obj) {
  obj.setActive(false);
  obj.setVisible(false);
  if (obj.body) {
    obj.body.stop();
    obj.body.enable = false;
  }
}

function getFootBand(player) {
  const halfH = SPRITES.foot.displayHeight / 2;
  return {
    top: player.y - halfH,
    bottom: player.y + halfH,
  };
}

/** Foot contact only when falling into the sneaker's vertical band. */
function canFootContact(player, obj) {
  if (!obj?.body || obj.getData('kicked')) return false;
  if (obj.body.velocity.y <= 0) return false;

  const band = getFootBand(player);
  const dickBottom = obj.y + SPRITES.dick.displayHeight / 2;
  return dickBottom >= band.top;
}

function bounceOffFoot(obj, player) {
  const now = obj.scene.time.now;
  if (now - (obj.getData('lastFootBounce') || 0) < 180) return false;

  obj.setData('lastFootBounce', now);
  obj.setData('hasBouncedFoot', true);

  const speed = Phaser.Math.Between(200, 300);
  const halfFoot = SPRITES.foot.displayWidth / 2;
  const relX = Phaser.Math.Clamp((obj.x - player.x) / halfFoot, -1, 1);
  obj.setVelocity(relX * speed * 0.85, -speed);

  return true;
}

function kickObject(obj, playerX) {
  if (obj.getData('kicked')) return;

  obj.setData('kicked', true);
  const speed = Phaser.Math.Between(300, 440);
  const offset = (obj.x - playerX) / 40;
  obj.setVelocity(offset * 60, -speed);
  obj.setBounce(0, 0);
  obj.setCollideWorldBounds(false);
  if (obj.body) {
    obj.body.setAllowGravity(false);
  }
}

/** Miss = fell past the sneaker while falling downward. */
function isMissed(obj, player) {
  if (obj.getData('kicked')) return false;
  if (!obj.body || obj.body.velocity.y <= 0) return false;

  const band = getFootBand(player);
  const dickBottom = obj.y + SPRITES.dick.displayHeight / 2;
  return dickBottom > band.bottom + 2;
}

function isCleared(obj) {
  return obj.getData('kicked') && obj.y < -30;
}

function shouldBounceOnFoot(obj) {
  return obj.getData('trajectory') === TRAJECTORY.BOUNCE
    && !obj.getData('kicked')
    && !obj.getData('hasBouncedFoot')
    && obj.body
    && obj.body.velocity.y > 0;
}




class Player extends Phaser.Physics.Arcade.Sprite {
  constructor(scene, x, y) {
    super(scene, x, y, SPRITES.foot.key);
    scene.add.existing(this);
    scene.physics.add.existing(this);

    this.setDisplaySize(SPRITES.foot.displayWidth, SPRITES.foot.displayHeight);
    this.setImmovable(true);
    this.body.setAllowGravity(false);
    this.setDepth(10);
    this.body.setSize(SPRITES.foot.bodyWidth, SPRITES.foot.bodyHeight);
    this.body.setOffset(SPRITES.foot.bodyOffsetX, SPRITES.foot.bodyOffsetY);

    this.moveSpeed = 520;
    this.cursors = scene.input.keyboard?.createCursorKeys();
    this.keys = scene.input.keyboard?.addKeys('A,D') || {};

    scene.input.on('pointermove', this.onPointerMove, this);
    scene.input.on('pointerdown', this.onPointerMove, this);
  }

  onPointerMove(pointer) {
    if (this.scene.gamePaused) return;

    const half = this.scene.scale.height * 0.45;
    if (pointer.y >= half) {
      const limits = getFootMoveLimits(this.scene.scale.width);
      this.targetX = Phaser.Math.Clamp(pointer.x, limits.min, limits.max);
    }
  }

  preUpdate(time, delta) {
    super.preUpdate(time, delta);

    if (this.scene.gamePaused) {
      this.setVelocityX(0);
      return;
    }

    let vx = 0;
    if (this.cursors?.left.isDown || this.keys.A?.isDown) {
      vx = -this.moveSpeed;
    } else if (this.cursors?.right.isDown || this.keys.D?.isDown) {
      vx = this.moveSpeed;
    }

    if (this.targetX !== undefined) {
      const dx = this.targetX - this.x;
      if (Math.abs(dx) > 2) {
        vx = Phaser.Math.Clamp(dx * 8, -this.moveSpeed, this.moveSpeed);
      } else {
        this.x = this.targetX;
        vx = 0;
      }
    }

    this.setVelocityX(vx);

    const limits = getFootMoveLimits(this.scene.scale.width);
    this.x = Phaser.Math.Clamp(this.x, limits.min, limits.max);
  }

  destroy(fromScene) {
    if (this.scene?.input) {
      this.scene.input.off('pointermove', this.onPointerMove, this);
      this.scene.input.off('pointerdown', this.onPointerMove, this);
    }
    super.destroy(fromScene);
  }
}



class BootScene extends Phaser.Scene {
  constructor() {
    super('BootScene');
  }

  preload() {
    this.load.image('foot-src', "data:image/png;base64,");
    this.load.image('dick-src', "data:image/jpeg;base64,");
  }

  create() {
    try {
      const foot = makePixelTexture(this, 'foot-src', 'foot', SOURCE_TARGETS.foot);
      const dick = makePixelTexture(this, 'dick-src', 'dick', SOURCE_TARGETS.dick);
      applySpriteMetrics({ foot, dick });
      this.textures.remove('foot-src');
      this.textures.remove('dick-src');
      this.scene.start('MenuScene');
    } catch (err) {
      console.error(err);
      const { width, height } = this.scale;
      this.add.text(width / 2, height / 2, 'LOAD ERROR\n' + (err.message || err), {
        fontFamily: 'monospace',
        fontSize: '12px',
        color: '#ffffff',
        align: 'center',
      }).setOrigin(0.5);
    }
  }
}





class MenuScene extends Phaser.Scene {
  constructor() {
    super('MenuScene');
  }

  create() {
    const { width, height } = this.scale;
    const { level, highScore } = loadProgress();

    this.add.rectangle(width / 2, height / 2, width, height, 0x000000);

    this.add.text(width / 2, height * 0.22, 'DICKKICKER', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '22px',
      color: '#ffffff',
    }).setOrigin(0.5);

    this.add.text(width / 2, height * 0.32, '80s arcade edition', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '8px',
      color: '#888888',
    }).setOrigin(0.5);

    const startText = this.add.text(width / 2, height * 0.52, 'TAP TO START', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '12px',
      color: '#ffffff',
    }).setOrigin(0.5);

    this.tweens.add({
      targets: startText,
      alpha: 0.2,
      duration: 600,
      yoyo: true,
      repeat: -1,
    });

    this.add.text(width / 2, height * 0.62, `LEVEL ${level}`, {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '10px',
      color: '#888888',
    }).setOrigin(0.5);

    if (highScore > 0) {
      this.add.text(width / 2, height * 0.68, `HI ${highScore}`, {
        fontFamily: '"Press Start 2P", monospace',
        fontSize: '8px',
        color: '#888888',
      }).setOrigin(0.5);
    }

    this.add.text(width / 2, height * 0.82, 'drag sneaker to kick', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '7px',
      color: '#888888',
    }).setOrigin(0.5);

    this.add.text(width / 2, height * 0.9, 'hold 1.2s to reset', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '6px',
      color: '#444444',
    }).setOrigin(0.5);

    this.pointerDownAt = 0;
    this.input.on('pointerdown', () => {
      this.pointerDownAt = this.time.now;
      unlockAudio(this);
    });
    this.input.on('pointerup', () => {
      const held = this.time.now - this.pointerDownAt;
      if (held >= 1200) {
        resetProgress();
        this.scene.restart();
      } else {
        this.scene.start('GameScene', { level });
      }
    });
  }
}








class GameScene extends Phaser.Scene {
  constructor() {
    super('GameScene');
  }

  init(data) {
    this.currentLevel = data.level || 1;
    this.startLives = data.lives ?? 3;
    this.startScore = data.score ?? 0;
    this.levelConfig = getLevelConfig(this.currentLevel);
  }

  create() {
    const { width, height } = this.scale;

    unlockAudio(this);
    getAudio().ensureMusic(this);

    this.score = this.startScore;
    this.lives = this.startLives;
    this.spawned = 0;
    this.cleared = 0;
    this.levelComplete = false;
    this.gameOver = false;
    this.gamePaused = false;

    this.bounceBounds = getBounceBounds(width, height);
    this.physics.world.setBounds(
      this.bounceBounds.x,
      this.bounceBounds.y,
      this.bounceBounds.width,
      this.bounceBounds.height
    );

    this.add.rectangle(width / 2, height / 2, width, height, 0x000000);

    this.drawBorder(width, height);
    this.createHud(width, height);

    this.fallObjects = this.physics.add.group({
      classType: Phaser.Physics.Arcade.Sprite,
      maxSize: 512,
      runChildUpdate: false,
    });

    this.player = new Player(this, width / 2, height - SPRITES.foot.displayHeight / 2 - 20);

    this.physics.add.overlap(
      this.player,
      this.fallObjects,
      this.handleFootContact,
      canFootContact,
      this
    );

    this.physics.world.on('worldbounds', this.onWallBounce, this);

    this.spawnTimer = this.time.addEvent({
      delay: this.levelConfig.spawnIntervalMs,
      callback: this.spawnObject,
      callbackScope: this,
      loop: true,
    });

    this.spawnObject();
  }

  handleFootContact(player, obj) {
    if (obj.getData('kicked') || this.levelComplete || this.gameOver || this.gamePaused) return;

    if (shouldBounceOnFoot(obj)) {
      if (bounceOffFoot(obj, player)) {
        getAudio().playBounce();
        this.cameras.main.shake(40, 0.002);
      }
      return;
    }

    if (obj.body.velocity.y <= 0) return;

    kickObject(obj, player.x);
    getAudio().playKick();
    this.score += 10 * this.currentLevel;
    this.cameras.main.shake(60, 0.004);
    this.updateHud();
  }

  onWallBounce(body, _up, _down, left, right) {
    const obj = body.gameObject;
    if (!obj || !obj.getData('wallBounce') || obj.getData('kicked')) return;
    if (left || right) {
      getAudio().playBounce();
    }
  }

  shutdown() {
    this.physics.world.off('worldbounds', this.onWallBounce, this);
    if (this.spawnTimer) {
      this.spawnTimer.remove(false);
      this.spawnTimer = null;
    }
    if (this.player) {
      this.player.destroy(true);
      this.player = null;
    }
  }

  drawBorder(width, height) {
    const g = this.add.graphics();
    g.lineStyle(3, 0xffffff, 1);
    g.strokeRect(6, 6, width - 12, height - 12);
    g.lineStyle(1, 0x888888, 1);
    g.strokeRect(12, 12, width - 24, height - 24);
  }

  createHud(width, height) {
    this.levelText = this.add.text(16, 16, `LV ${this.currentLevel}`, {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '10px',
      color: '#ffffff',
    });

    this.scoreText = this.add.text(width / 2, 16, '0000', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '10px',
      color: '#ffffff',
    }).setOrigin(0.5, 0);

    this.livesText = this.add.text(width - 16, 16, '♥♥♥', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '10px',
      color: '#ffffff',
    }).setOrigin(1, 0);

    this.remainingText = this.add.text(width / 2, 36, '', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '7px',
      color: '#888888',
    }).setOrigin(0.5, 0);

    this.pauseBtn = this.add.text(width / 2, 54, '|| PAUSE', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '8px',
      color: '#ffffff',
      backgroundColor: '#222222',
      padding: { x: 8, y: 6 },
    }).setOrigin(0.5, 0).setInteractive({ useHandCursor: true });

    this.pauseBtn.on('pointerup', () => {
      this.togglePause();
    });

    this.pauseOverlay = this.add.text(width / 2, height / 2, 'PAUSED', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '20px',
      color: '#ffffff',
    }).setOrigin(0.5).setDepth(100).setVisible(false);

    this.updateHud();
  }

  togglePause() {
    if (this.levelComplete || this.gameOver) return;

    this.gamePaused = !this.gamePaused;

    if (this.gamePaused) {
      this.physics.pause();
      this.time.paused = true;
      getAudio().pauseMusic();
      this.pauseBtn.setText('> RESUME');
      this.pauseOverlay.setVisible(true);
    } else {
      this.physics.resume();
      this.time.paused = false;
      getAudio().resumeMusic();
      this.pauseBtn.setText('|| PAUSE');
      this.pauseOverlay.setVisible(false);
    }
  }

  updateHud() {
    this.scoreText.setText(String(this.score).padStart(4, '0'));
    this.livesText.setText('♥'.repeat(this.lives));
    const left = this.levelConfig.totalObjects - this.cleared;
    this.remainingText.setText(`${left} left`);
  }

  spawnObject() {
    if (this.levelComplete || this.gameOver || this.gamePaused) return;
    if (this.spawned >= this.levelConfig.totalObjects) {
      this.spawnTimer.remove(false);
      return;
    }

    const { width } = this.scale;
    const margin = this.bounceBounds.insetX + SPRITES.dick.displayWidth / 2;
    const x = Phaser.Math.Between(margin, width - margin);

    const spawnConfig = { ...this.levelConfig };
    if (Math.random() > this.levelConfig.fastRatio) {
      spawnConfig.speedMax = Math.min(spawnConfig.speedMax, spawnConfig.speedMin + 30);
    }

    const obj = createFallObject(this.fallObjects, x, 20, spawnConfig);
    if (obj) {
      this.spawned += 1;
    } else if (this.spawned < this.levelConfig.totalObjects) {
      this.time.delayedCall(80, this.spawnObject, [], this);
    }
  }

  update() {
    if (this.levelComplete || this.gameOver || this.gamePaused) return;
    if (!this.player?.active) return;

    try {
      this.tickObjects();
    } catch (err) {
      console.error('Game tick error:', err);
    }
  }

  tickObjects() {
    const toRemove = [];
    const children = this.fallObjects.getChildren();

    for (let i = 0; i < children.length; i += 1) {
      const obj = children[i];
      if (!obj.active) continue;

      if (isMissed(obj, this.player)) {
        if (!obj.getData('missed')) {
          obj.setData('missed', true);
          this.loseLife();
        }
        toRemove.push(obj);
      } else if (isCleared(obj)) {
        this.cleared += 1;
        this.score += 25;
        toRemove.push(obj);
        this.updateHud();
        this.checkLevelComplete();
      }
    }

    toRemove.forEach((obj) => releaseFallObject(obj));

    this.checkWaveEnd();
  }

  loseLife() {
    if (this.gameOver || this.levelComplete) return;

    this.lives -= 1;
    this.score = Math.max(0, this.score - 25 * this.currentLevel);
    getAudio().playAw();
    this.updateHud();
    this.cameras.main.flash(200, 255, 255, 255);

    if (this.lives <= 0) {
      this.endGame(false);
    }
  }

  checkWaveEnd() {
    if (this.levelComplete || this.gameOver) return;
    if (this.spawned < this.levelConfig.totalObjects) return;

    const active = this.fallObjects.countActive(true);
    if (active > 0) return;

    if (this.cleared >= this.levelConfig.totalObjects) {
      this.completeLevel();
    } else if (this.lives > 0) {
      this.retryLevel();
    } else {
      this.endGame(false);
    }
  }

  retryLevel() {
    this.gameOver = true;
    const { width } = this.scale;
    const banner = this.add.text(width / 2, this.scale.height * 0.55, 'MISSED TOO MANY', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '10px',
      color: '#ffffff',
    }).setOrigin(0.5);

    const payload = {
      level: this.currentLevel,
      lives: this.lives,
      score: this.score,
    };

    this.time.delayedCall(1500, () => {
      banner.destroy();
      this.scene.restart(payload);
    });
  }

  checkLevelComplete() {
    if (this.cleared < this.levelConfig.totalObjects) return;
    this.checkWaveEnd();
  }

  completeLevel() {
    if (this.levelComplete) return;
    this.levelComplete = true;
    this.gameOver = true;

    if (this.spawnTimer) {
      this.spawnTimer.remove(false);
      this.spawnTimer = null;
    }

    const nextLevel = Math.min(MAX_LEVEL, this.currentLevel + 1);
    saveProgress(nextLevel, this.score);

    const { width, height } = this.scale;
    const bannerText = this.currentLevel >= MAX_LEVEL ? 'YOU WIN!' : 'LEVEL CLEAR';
    const banner = this.add.text(width / 2, height / 2, bannerText, {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '16px',
      color: '#ffffff',
    }).setOrigin(0.5);

    this.tweens.add({ targets: banner, alpha: 0.3, duration: 400, yoyo: true, repeat: 2 });

    this.time.delayedCall(1800, () => {
      if (this.currentLevel >= MAX_LEVEL) {
        saveProgress(MAX_LEVEL, this.score);
        this.scene.start('MenuScene');
      } else {
        this.scene.restart({
          level: this.currentLevel + 1,
          lives: this.lives,
          score: this.score,
        });
      }
    });
  }

  showVictory() {
    // kept for compatibility; level 80 handled in completeLevel
    this.scene.start('MenuScene');
  }

  endGame(won) {
    if (this.gameOver) return;
    this.gameOver = true;
    saveProgress(this.currentLevel, this.score);
    this.scene.start('GameOverScene', {
      score: this.score,
      level: this.currentLevel,
      won,
    });
  }
}



class GameOverScene extends Phaser.Scene {
  constructor() {
    super('GameOverScene');
  }

  init(data) {
    this.finalScore = data.score || 0;
    this.finalLevel = data.level || 1;
  }

  create() {
    const { width, height } = this.scale;

    this.add.rectangle(width / 2, height / 2, width, height, 0x000000);

    this.add.text(width / 2, height * 0.3, 'GAME OVER', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '20px',
      color: '#ffffff',
    }).setOrigin(0.5);

    this.add.text(width / 2, height * 0.45, `SCORE ${this.finalScore}`, {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '12px',
      color: '#888888',
    }).setOrigin(0.5);

    this.add.text(width / 2, height * 0.52, `LEVEL ${this.finalLevel}`, {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '10px',
      color: '#888888',
    }).setOrigin(0.5);

    const retry = this.add.text(width / 2, height * 0.68, 'TAP TO RETRY', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '11px',
      color: '#ffffff',
    }).setOrigin(0.5);

    this.tweens.add({
      targets: retry,
      alpha: 0.2,
      duration: 500,
      yoyo: true,
      repeat: -1,
    });

    this.add.text(width / 2, height * 0.82, 'TAP MENU FOR TITLE', {
      fontFamily: '"Press Start 2P", monospace',
      fontSize: '7px',
      color: '#444444',
    }).setOrigin(0.5);

    this.input.once('pointerup', (pointer) => {
      if (pointer.y > height * 0.75) {
        this.scene.start('MenuScene');
      } else {
        this.scene.start('GameScene', { level: this.finalLevel });
      }
    });
  }
}







const config = {
  type: Phaser.AUTO,
  parent: 'game-container',
  backgroundColor: '#000000',
  scale: {
    mode: Phaser.Scale.RESIZE,
    autoCenter: Phaser.Scale.CENTER_BOTH,
    width: 360,
    height: 640,
  },
  physics: {
    default: 'arcade',
    arcade: {
      gravity: { y: 0 },
      debug: false,
    },
  },
  scene: [BootScene, MenuScene, GameScene, GameOverScene],
};

new Phaser.Game(config);

})();